define('tiny_imageia/configuration',['editor_tiny/utils'],function(TinyUtils){'use strict';const buttonName='tiny_imageia_imageia';const menuItemName='tiny_imageia_imageia';const getToolbarConfiguration=(instanceConfig)=>{let toolbar=instanceConfig.toolbar;toolbar=TinyUtils.addToolbarButtons(toolbar,'content',[buttonName]);return toolbar;};const getMenuConfiguration=(instanceConfig)=>{let menu=instanceConfig.menu;menu=TinyUtils.addMenubarItem(menu,'insert',[menuItemName].join(' '));return menu;};const configure=(instanceConfig)=>({toolbar:getToolbarConfiguration(instanceConfig),menu:getMenuConfiguration(instanceConfig)});return{configure};});
